import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as n,o as i,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Přidání kanálu Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/google-drive.md","filePath":"cs-CZ/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"cs-CZ/upload/google-drive.md"};function p(c,e,h,k,u,g){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="pridani-kanalu-google-drive" tabindex="-1">Přidání kanálu Google Drive <a class="header-anchor" href="#pridani-kanalu-google-drive" aria-label="Permalink to &quot;Přidání kanálu Google Drive&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><p>Připravte si:</p><table tabindex="0"><thead><tr><th>Požadavek</th><th>Proč je potřeba</th></tr></thead><tbody><tr><td>Účet Google</td><td>Pro přístup do Google Cloud a autorizaci Google Drive</td></tr><tr><td>Projekt Google Cloud</td><td>Pro zapnutí Drive API a vytvoření OAuth údajů</td></tr><tr><td>OAuth 2.0 klient</td><td>Umožní ImgBed získat <code>Client ID</code>, <code>Client Secret</code> a <code>Refresh Token</code></td></tr><tr><td>Vaše doména ImgBed</td><td>Pro OAuth redirect URI. Musí odpovídat doméně, kterou skutečně používáte.</td></tr></tbody></table><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="krok-1-zapnete-google-drive-api" tabindex="-1">Krok 1: Zapněte Google Drive API <a class="header-anchor" href="#krok-1-zapnete-google-drive-api" aria-label="Permalink to &quot;Krok 1: Zapněte Google Drive API&quot;">​</a></h3><ol><li>Otevřete Google Cloud Console.</li><li>Vytvořte nový projekt nebo vyberte existující.</li><li>Přejděte do <code>APIs &amp; Services</code>.</li><li>Klikněte na <code>Enable APIs and Services</code>.</li><li>Vyhledejte <code>Google Drive API</code>.</li><li>Otevřete ji a zapněte.</li></ol><h3 id="krok-2-nastavte-oauth-consent-screen" tabindex="-1">Krok 2: Nastavte OAuth consent screen <a class="header-anchor" href="#krok-2-nastavte-oauth-consent-screen" aria-label="Permalink to &quot;Krok 2: Nastavte OAuth consent screen&quot;">​</a></h3><ol><li>V Google Cloud otevřete <code>Google Auth Platform</code>.</li><li>Vyplňte základní údaje v <code>Branding</code>, například název aplikace, e-mail podpory a kontakt vývojáře.</li><li>Otevřete <code>Audience</code>.</li><li>Pro většinu osobních self-hosted instalací zvolte <code>External</code>.</li><li>Pokud zvolíte <code>External</code>, přidejte Google účet, který chcete autorizovat, do <code>Test users</code>.</li><li>Otevřete <code>Data Access</code>.</li><li>Přidejte požadovaná oprávnění Google Drive.</li></ol><h3 id="krok-3-vytvorte-oauth-2-0-klienta" tabindex="-1">Krok 3: Vytvořte OAuth 2.0 klienta <a class="header-anchor" href="#krok-3-vytvorte-oauth-2-0-klienta" aria-label="Permalink to &quot;Krok 3: Vytvořte OAuth 2.0 klienta&quot;">​</a></h3><ol><li>V <code>Google Auth Platform</code> otevřete <code>Clients</code>.</li><li>Vytvořte nového klienta.</li><li>Typ aplikace nastavte na <code>Web application</code>.</li><li>Dejte klientovi srozumitelný název.</li><li>Do authorized JavaScript origins zadejte URL ImgBed, například:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>Do authorized redirect URIs zadejte:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="Vytvoření OAuth klienta" loading="lazy"></p><p><img src="'+a+'" alt="Zadání domény a callback URL" loading="lazy"></p><p>Po vytvoření zkopírujte:</p><table tabindex="0"><thead><tr><th>Vygenerovaná hodnota</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="krok-4-vyplnte-kanal-google-drive" tabindex="-1">Krok 4: Vyplňte kanál Google Drive <a class="header-anchor" href="#krok-4-vyplnte-kanal-google-drive" aria-label="Permalink to &quot;Krok 4: Vyplňte kanál Google Drive&quot;">​</a></h2><p>V Nastavení nahrávání zvolte <code>Google Drive</code> a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co zadat</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID z Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret z Google Cloud</td></tr><tr><td>Refresh Token</td><td>Zatím nechte prázdné. Získáte ho v dalším kroku.</td></tr><tr><td>Kořenový adresář</td><td>Volitelné. Výchozí je <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Vyplnění údajů klienta v ImgBed" loading="lazy"></p><h2 id="krok-5-ziskejte-refresh-token" tabindex="-1">Krok 5: Získejte Refresh Token <a class="header-anchor" href="#krok-5-ziskejte-refresh-token" aria-label="Permalink to &quot;Krok 5: Získejte Refresh Token&quot;">​</a></h2><ol><li>Klikněte na <code>Get Token</code>.</li><li>Vyberte Google účet, který chcete připojit.</li><li>Dokončete autorizační kroky.</li><li>Callback stránka zobrazí <code>Refresh Token</code>.</li><li>Zkopírujte ho.</li><li>Vraťte se do ImgBed a vložte ho do <code>Refresh Token</code>.</li></ol><p><img src="'+l+`" alt="Kopírování Refresh Token po autorizaci" loading="lazy"></p><p>Pokud později změníte Google účet, OAuth klienta nebo stará autorizace vyprší, nemusíte kanál mazat. Otevřete stránku úprav a klikněte na <code>Reauthorize</code>.</p><h2 id="krok-6-ulozte-kanal" tabindex="-1">Krok 6: Uložte kanál <a class="header-anchor" href="#krok-6-ulozte-kanal" aria-label="Permalink to &quot;Krok 6: Uložte kanál&quot;">​</a></h2><p>Po vyplnění všech polí kanál uložte.</p><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete Google Cloud</span></span>
<span class="line"><span>-&gt; Vytvořte nebo vyberte projekt</span></span>
<span class="line"><span>-&gt; Zapněte Google Drive API</span></span>
<span class="line"><span>-&gt; Nastavte Google Auth Platform</span></span>
<span class="line"><span>-&gt; Pokud je Audience External, přidejte svůj Google účet do Test users</span></span>
<span class="line"><span>-&gt; Vytvořte OAuth klienta typu Web application</span></span>
<span class="line"><span>-&gt; Použijte https://your-domain.com/api/oauth/google/callback jako redirect URI</span></span>
<span class="line"><span>-&gt; Zadejte Client ID a Client Secret do ImgBed</span></span>
<span class="line"><span>-&gt; Klikněte Get Token</span></span>
<span class="line"><span>-&gt; Přihlaste se přes Google a autorizujte</span></span>
<span class="line"><span>-&gt; Zkopírujte Refresh Token z callback stránky</span></span>
<span class="line"><span>-&gt; Vložte ho zpět do ImgBed a uložte</span></span>
<span class="line"><span>-&gt; Nahrajte testovací obrázek</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const y=n(d,[["render",p]]);export{m as __pageData,y as default};
